  class SQLQueryValidator {
    private val dangerousKeywords = Set(
      "DROP", "DELETE", "TRUNCATE", "INSERT", "UPDATE", 
      "CREATE", "ALTER", "GRANT", "REVOKE", "MERGE"
    )
    
    private val allowedKeywords = Set(
      "SELECT", "FROM", "WHERE", "GROUP", "ORDER", "HAVING",
      "JOIN", "LEFT", "RIGHT", "INNER", "OUTER", "ON", "AS",
      "LIMIT", "DISTINCT", "UNION", "WITH", "BY", "AND", "OR"
    )
    
    def validateQuery(query: String): Either[String, String] = {
      val normalizedQuery = query.toUpperCase.trim
      
      if (normalizedQuery.isEmpty) {
        return Left("Query cannot be empty")
      }
      
      if (!normalizedQuery.startsWith("SELECT") && !normalizedQuery.startsWith("WITH")) {
        return Left("Only SELECT and WITH queries are allowed")
      }
      
      val tokens = normalizedQuery.split("\\s+")
      val foundDangerous = tokens.filter(dangerousKeywords.contains)
      
      if (foundDangerous.nonEmpty) {
        return Left(s"Query contains forbidden operations: ${foundDangerous.mkString(", ")}")
      }
      
      if (normalizedQuery.contains(";") && normalizedQuery.indexOf(";") < normalizedQuery.length - 1) {
        return Left("Multiple statements not allowed")
      }
      
      if (normalizedQuery.contains("--") || normalizedQuery.contains("/*")) {
        return Left("Comments not allowed in queries")
      }
      
      Right(query)
    }
    
    def validateLogicalPlan(plan: LogicalPlan): Either[String, LogicalPlan] = {
      val planString = plan.toString.toUpperCase
      
      if (planString.contains("INSERTINTO") || 
          planString.contains("CREATETABLE") ||
          planString.contains("DROPTABLE")) {
        Left("Query plan contains forbidden operations")
      } else {
        Right(plan)
      }
    }
  }
  
  class QueryExecutor(spark: SparkSession, validator: SQLQueryValidator) {
    
    def executeQuery(request: QueryRequest): QueryResponse = {
      val startTime = System.currentTimeMillis()
      
      validator.validateQuery(request.query) match {
        case Left(error) =>
          QueryResponse(
            success = false,
            error = Some(s"Validation failed: $error"),
            executionTimeMs = System.currentTimeMillis() - startTime
          )
        
        case Right(validatedQuery) =>
          Try {
            spark.sparkContext.setJobGroup(
              s"user-query-${request.userId}-${startTime}",
              s"User: ${request.userId}, Query: ${request.query.take(100)}"
            )
            
            val sanitizedQuery = validatedQuery.replaceAll(";\\s*$", "")
            
            val df = spark.sql(sanitizedQuery)
            
            validator.validateLogicalPlan(df.queryExecution.logical) match {
              case Left(error) =>
                QueryResponse(
                  success = false,
                  error = Some(error),
                  executionTimeMs = System.currentTimeMillis() - startTime
                )
              
              case Right(_) =>
                val maxRows = request.maxRows.getOrElse(10000)
                val limitedDf = df.limit(maxRows)
                
                val schema = limitedDf.schema.fieldNames.toSeq
                val rows = limitedDf.collect()
                
                val data = rows.map { row =>
                  schema.zip(row.toSeq).map {
                    case (fieldName, value) =>
                      fieldName -> (if (value == null) None else value)
                  }.toMap
                }.toSeq
                
                val executionTime = System.currentTimeMillis() - startTime
                
                QueryResponse(
                  success = true,
                  data = Some(data),
                  schema = Some(schema),
                  rowCount = rows.length,
                  executionTimeMs = executionTime
                )
            }
          } match {
            case Success(response) => response
            case Failure(e: ParseException) =>
              QueryResponse(
                success = false,
                error = Some(s"SQL parse error: ${e.getMessage}"),
                executionTimeMs = System.currentTimeMillis() - startTime
              )
            case Failure(e) =>
              QueryResponse(
                success = false,
                error = Some(s"Query execution failed: ${e.getMessage}"),
                executionTimeMs = System.currentTimeMillis() - startTime
              )
          } match {
            case response =>
              spark.sparkContext.clearJobGroup()
              response
          }
      }
    }
    
    def executeQueryAsync(request: QueryRequest): scala.concurrent.Future[QueryResponse] = {
      import scala.concurrent.ExecutionContext.Implicits.global
      scala.concurrent.Future {
        executeQuery(request)
      }
    }
  }
  
