    def registerCustomersTable(path: String): Unit = {
      val df = spark.read.parquet(path)
      df.createOrReplaceTempView("customers")
    }
    
    def registerOrdersTable(path: String): Unit = {
      val df = spark.read.parquet(path)
      df.createOrReplaceTempView("orders")
    }
    
    def registerProductsTable(path: String): Unit = {
      val df = spark.read.parquet(path)
      df.createOrReplaceTempView("products")
    }
    
    def registerTransactionsTable(path: String): Unit = {
      val df = spark.read.parquet(path)
      df.createOrReplaceTempView("transactions")
    }
    
    def registerCustomTable(tableName: String, path: String, format: String = "parquet"): Unit = {
      val df = format.toLowerCase match {
        case "parquet" => spark.read.parquet(path)
        case "json" => spark.read.json(path)
        case "csv" => spark.read.option("header", "true").csv(path)
        case "orc" => spark.read.orc(path)
        case _ => throw new IllegalArgumentException(s"Unsupported format: $format")
      }
      df.createOrReplaceTempView(tableName)
    }
    
    def listAvailableTables(): Seq[String] = {
      spark.catalog.listTables().collect().map(_.name).toSeq
    }
